private void backtrack(int n, int start, List current, List> result) {
    if (n == 1) {
        if (current.size() > 1) {
            result.add(new ArrayList<>(current));
        }
        return;
    }

    for (int i = start; i <= n; i++) {
        if (n % i == 0) {
            current.add(i);
            backtrack(n / i, i, current, result);
            current.remove(current.size() - 1);
        }
    }
}

