from typing import List

def getFactors(n: int) -> List[List[int]]:
    result: List[List[int]] = []

    def backtrack(remaining: int, start: int, current: List[int]) -> None:
        if remaining == 1:
            if len(current) > 1:
                result.append(list(current))
            return
        for i in range(start, remaining + 1):
            if remaining % i == 0:
                current.append(i)
                backtrack(remaining // i, i, current)
                current.pop()

    backtrack(n, 2, [])
    return result
